    priority_queue<long long> pq;

    long long total = 0;
    int activeCount = 0;

    for (auto& elem : elements) {
        long long val = elem.first;
        long long lim = elem.second;

        // Check if we can activate this element
        if (activeCount < lim) {
            // Activate the element
            total += val;
            pq.push(lim);
            activeCount++;
        } else {
            // This element cannot be activated now, so we skip it
            continue;
        }

        // After activating, check which elements become inactive
        while (!pq.empty() && pq.top() <= activeCount) {
            pq.pop();
        }
    }

    return total;
}

